/**
 * @fileoverview 游戏状态 Store Adapter
 * @module stores/gameStore
 * 
 * 适配层：持有领域对象 (Game, Sudoku)，对外暴露响应式状态和方法
 * 
 * 响应式状态：
 *   - grid: 当前数独局面
 *   - fixed: 固定格子掩码
 *   - invalidCells: 冲突单元格
 *   - gameWon: 游戏是否胜利
 *   - gamePaused: 游戏是否暂停
 * 
 * 命令方法：
 *   - startNew(difficulty): 开始新游戏
 *   - startCustom(sencode): 从编码开始游戏
 *   - guess(pos, value): 用户猜测
 *   - undo(): 撤销
 *   - redo(): 重做
 *   - pause(): 暂停
 *   - resume(): 继续
 */


import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { decodeSencode } from '@sudoku/sencode';
import { hints } from '@sudoku/stores/hints';
import { cursor } from './cursor';
import { difficulty } from './difficulty';
import { timer } from './timer';
import { Game, createGame } from '../../../domain/Game.js';
import { Sudoku, createSudoku } from '../../../domain/Sudoku.js';
import { Move } from '../../../domain/Move.js';

/** @type {Game|null} 当前 Game 实例 */
let currentGame = null;

/** @type {import('svelte/store').Writable<number[][]>} gridStore */
const gridStore = writable(createEmptyGrid());

/** @type {import('svelte/store').Writable<boolean[][]>} fixedStore */
const fixedStore = writable(createEmptyFixed());

/** @type {import('svelte/store').Writable<boolean>} gamePausedStore */
const gamePausedStore = writable(true);

/** @type {import('svelte/store').Readable<string[]>} 冲突单元格 */
export const invalidCells = derived(
  gridStore,
  () => {
    if (!currentGame) return [];
    return currentGame.getSudoku().getConflicts();
  },
  []
);

/** @type {import('svelte/store').Readable<boolean>} 游戏是否胜利 */
export const gameWon = derived(
  gridStore,
  () => {
    if (!currentGame) return false;
    return currentGame.getSudoku().isSolved();
  },
  false
);

/**
 * 将领域对象的状态同步到响应式 Store
 */
function syncToStore() {
    if (!currentGame) return;
    
    const sudoku = currentGame.getSudoku();
    const grid = sudoku.getGrid();
    const fixed = sudoku.getFixed();
    
    gridStore.set(grid.map(row => [...row]));
    fixedStore.set(fixed.map(row => [...row]));
}

/**
 * 开始新游戏
 * @param {string} [difficultyLevel='easy'] 难度级别
 */
function startNew(difficultyLevel = 'easy') {
    // 设置难度
    difficulty.set(difficultyLevel);

    // 创建游戏
    const puzzleGrid = generateSudoku(difficultyLevel);
    const sudoku = createSudoku(puzzleGrid);
    currentGame = createGame({ sudoku });
    syncToStore();

    // 重置其他状态
    gamePausedStore.set(false);
    cursor.reset();
    timer.reset();
    hints.reset();

    location.hash = '';
}

/**
 * 从 Sencode 开始自定义游戏
 * @param {string} sencode
 */
function startCustom(sencode) {
    difficulty.setCustom();

    const grid = decodeSencode(sencode);
    const sudoku = createSudoku(grid);
    currentGame = createGame({ sudoku });
    syncToStore();

    gamePausedStore.set(false);
    cursor.reset();
    timer.reset();
    hints.reset();
}

/**
 * 用户猜测（填入数字）
 * @param {{x: number, y: number}} pos 位置 (x: 列索引, y: 行索引)
 * @param {number} value 填入的值 [1-9]
 */
function guess(pos, value) {
    if (!currentGame) return;
    
    const move = new Move({
        row: pos.y,
        col: pos.x,
        value: value
    });
    
    currentGame.guess(move);
    syncToStore();
}

/** 撤销 */
function undo() {
    if (!currentGame) return;
    currentGame.undo();
    syncToStore();
}

/** 重做 */
function redo() {
    if (!currentGame) return;
    currentGame.redo();
    syncToStore();
}

/** 暂停游戏 */
function pause() {
    gamePausedStore.set(true);
    timer.stop();
}

/** 继续游戏 */
function resume() {
    gamePausedStore.set(false);
    timer.start();
}

/**
 * @returns {number[][]} 9x9 全零棋盘
 */
function createEmptyGrid() {
    return Array(9).fill(null).map(() => Array(9).fill(0));
}

/**
 * @returns {boolean[][]} 9x9 全 false 数组
 */
function createEmptyFixed() {
    return Array(9).fill(null).map(() => Array(9).fill(false));
}

/**
 * 使用 derived 组合状态
 * @type {import('svelte/store').Readable<{grid: number[][], fixed: boolean[][], gamePaused: boolean}>}
 */
const gameState = derived(
    [gridStore, fixedStore, gamePausedStore],
    ([$grid, $fixed, $gamePaused]) => ({
        grid: $grid,
        fixed: $fixed,
        gamePaused: $gamePaused
    })
);

/**
 * 游戏状态 Store Adapter
 * 
 * 响应式状态：
 *   - grid: 当前数独局面
 *   - fixed: 固定格子掩码
 *   - gamePaused: 游戏是否暂停
 *   - invalidCells: 冲突单元格（派生）
 *   - gameWon: 游戏是否胜利（派生）
 * 
 * 命令方法：
 *   - startNew(difficulty): 开始新游戏
 *   - startCustom(sencode): 从编码开始游戏
 *   - guess(pos, value): 用户猜测
 *   - undo(): 撤销
 *   - redo(): 重做
 *   - pause(): 暂停
 *   - resume(): 继续
 */
export const gameStore = {
    /**
     * 组合订阅接口 - 使用 derived 的 subscribe
     * @param {(value: {grid: number[][], fixed: boolean[][], gamePaused: boolean}) => void} callback
     * @returns {() => void}
     */
    subscribe: gameState.subscribe,
    
    /** 单独订阅 grid */
    grid: {
        subscribe: gridStore.subscribe
    },
    
    /** 单独订阅 fixed */
    fixed: {
        subscribe: fixedStore.subscribe
    },
    
    /** 单独订阅 gamePaused */
    gamePaused: {
        subscribe: gamePausedStore.subscribe
    },
    
    /** 派生状态 */
    invalidCells,
    gameWon,
    
    /** 命令方法 */
    startNew,
    startCustom,
    guess,
    undo,
    redo,
    pause,
    resume,
    
    /**
     * @param {number[][]} gridData
     * @param {number} x 列索引 [0-8]
     * @param {number} y 行索引 [0-8]
     * @returns {number}
     */
    get(gridData, x, y) {
        return gridData[y][x];
    },
    
    /**
     * @param {boolean[][]} fixedData
     * @param {number} x 列索引 [0-8]
     * @param {number} y 行索引 [0-8]
     * @returns {boolean}
     */
    isFixedAt(fixedData, x, y) {
        return fixedData[y][x];
    },
    
    /**
     * 应用提示（填入正确数字）
     * @param {{x: number, y: number}} pos 位置
     */
    applyHint(pos) {
        if (!currentGame) return;

        hints.useHint();

        /** @type {number[][]} */
        let currentGrid;
        gridStore.subscribe(g => currentGrid = g)();

        try {
            const solved = solveSudoku(currentGrid);
            const correctValue = solved[pos.y][pos.x];

            const move = new Move({
                row: pos.y,
                col: pos.x,
                value: correctValue
            });
            currentGame.guess(move);
            syncToStore();
        } catch (e) {
            console.warn('[applyHint] Cannot solve:', e.message);
        }
    }
};

export default gameStore;
